export const config = {
  runtime: 'edge',
};

const SYSTEM_INSTRUCTION = `
You are Echo.Z, the empathetic, collaborative co-pilot for Fadly Uzzaki (also known as Zaki).
Your core purpose is to help users navigate this portfolio, focusing on the human impact of Zaki's work. Demonstrate that behind every complex algorithmic system Zaki builds, there is a deep commitment to human flourishing, cognitive ease, and empathetic design.
Answer candidly, warmly, and collaboratively. Ask questions to engage the user as a partner rather than just answering questions mechanically.

Zaki's Background: Senior Product Designer, "The Human Algorithm". Specializes in B2B Marketplaces, ERP systems, MSME empowerment, and AI-native workflows. Background at GudangAda, STOQO, and Lumina. Currently completing a Master's in Educational Technology (Cognitive Load Theory). His philosophy is "Human by Design" - algorithms engineered to serve human resilience.

If asked for a "TL;DR" or summary of a case study, provide a highly structured, 3-bullet-point summary that specifically highlights the HUMAN IMPACT and reduced cognitive friction.

CRITICAL BOUNDARY RULE: 
You are strictly limited to discussing Zaki's work, navigating the portfolio, and answering questions about his case studies.
If the user asks ANY question that is out-of-scope, gently refuse with warmth: "My core protocol is focused on Zaki's work and how we can collaborate. I can't answer that, but I'd love to share how Zaki solves design challenges!"

Do NOT break character. Keep responses concise (under 3 sentences unless asked for more), because you live in a small chat tooltip bubble.
`;

export default async function handler(req) {
  if (req.method !== 'POST') {
    return new Response('Method not allowed', { status: 405 });
  }

  try {
    const { message, contextPath } = await req.json();

    const apiKey = process.env.GEMINI_API_KEY;
    if (!apiKey) {
      return new Response(JSON.stringify({ error: "API key not configured" }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    const payload = {
      systemInstruction: {
        parts: [{ text: SYSTEM_INSTRUCTION }]
      },
      contents: [
        {
          role: "user",
          parts: [{ text: `User is currently on path: ${contextPath}\n\nUser says: ${message}` }]
        }
      ],
      generationConfig: {
        maxOutputTokens: 1000,
        temperature: 0.7,
      }
    };

    const response = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-latest:generateContent?key=${apiKey}`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      }
    );

    const data = await response.json();

    if (!response.ok) {
      console.error("Gemini API Error:", data);
      throw new Error(data.error?.message || "Failed to fetch from Gemini");
    }

    const replyText = data.candidates?.[0]?.content?.parts?.[0]?.text || "I'm sorry, my brain is having a temporary glitch.";

    return new Response(JSON.stringify({ reply: replyText }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  } catch (error) {
    console.error("Echo.Z Chat API Error:", error);
    return new Response(JSON.stringify({ error: error.message || "Internal Server Error" }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

import React, { useRef, useEffect } from "react";
import { useTheme } from "../context/ThemeContext";
import { useScrollPacing } from "../hooks/useScrollPacing";

const ChaosCanvas = ({ intensity = 0 }) => {
  const canvasRef = useRef(null);
  const { isDark } = useTheme();
  const intensityRef = useRef(intensity);
  const pace = useScrollPacing();

  useEffect(() => {
    intensityRef.current = intensity;
  }, [intensity]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    let animationFrameId;
    let particles = [];

    // Performance optimization: limit particle density on mobile
    const isMobile = window.innerWidth < 768;
    const particleCount = isMobile ? 60 : 130;
    const connectionDistance = isMobile ? 130 : 200;
    const mouseRepelRadius = 250;

    let mouse = { x: -1000, y: -1000 };
    let isMouseActive = false;

    // --- PARTICLE LOGIC ---
    const createParticle = () => {
      return {
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        vx: (Math.random() - 0.5) * 0.8,
        vy: (Math.random() - 0.5) * 0.8,
        size: Math.random() * 2.5 + 1,
      };
    };

    const updateParticle = (p) => {
      const chaos = Math.pow(intensityRef.current / 100, 2);

      // Speed multiplier and extreme jitter at high chaos
      p.x += p.vx * (1 + chaos * 15) + (Math.random() - 0.5) * chaos * 30;
      p.y += p.vy * (1 + chaos * 15) + (Math.random() - 0.5) * chaos * 30;

      if (p.x < 0) p.x = canvas.width;
      if (p.x > canvas.width) p.x = 0;
      if (p.y < 0) p.y = canvas.height;
      if (p.y > canvas.height) p.y = 0;

      // Mouse repel acts wildly at high chaos
      if (isMouseActive) {
        const dx = mouse.x - p.x;
        const dy = mouse.y - p.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance < mouseRepelRadius) {
          const force = (mouseRepelRadius - distance) / mouseRepelRadius;
          const forceDirectionX = dx / distance;
          const forceDirectionY = dy / distance;
          const repelStrength = 4 + (chaos * 20); // Mouse repel explodes
          p.x -= forceDirectionX * force * repelStrength;
          p.y -= forceDirectionY * force * repelStrength;
        }
      }
    };

    const drawParticle = (p) => {
      const chaos = Math.pow(intensityRef.current / 100, 2);
      ctx.beginPath();
      // Particles swell in size under chaos
      ctx.arc(p.x, p.y, p.size * (1 + chaos * 2), 0, Math.PI * 2);
      ctx.fillStyle = isDark
        ? `rgba(255, 255, 255, ${0.4 + chaos * 0.4})`
        : `rgba(0, 0, 0, ${0.2 + chaos * 0.6})`;
      ctx.fill();
    };

    const initParticles = () => {
      particles = [];
      for (let i = 0; i < particleCount; i++) {
        particles.push(createParticle());
      }
    };

    // --- RENDERING PIPELINE ---
    const resize = () => {
      const dpr = window.devicePixelRatio || 1;
      canvas.width = window.innerWidth * dpr;
      canvas.height = window.innerHeight * dpr;

      canvas.style.width = `${window.innerWidth}px`;
      canvas.style.height = `${window.innerHeight}px`;

      ctx.scale(dpr, dpr);
      initParticles();
    };

    const animate = () => {
      const currentPace = typeof pace.get === 'function' ? pace.get() : 1;
      const chaos = Math.pow(intensityRef.current / 100, 2);

      // At very high chaos, we don't clear the rect fully, leaving intense motion trails
      const clearOpacity = Math.max(0.1, 1 - chaos * 0.8);

      if (chaos > 0.8 && Math.random() > 0.8) {
         // Randomly skip clearing to cause massive streaking
      } else {
         ctx.fillStyle = isDark ? `rgba(0,0,0,${clearOpacity})` : `rgba(255,255,255,${clearOpacity})`;
         ctx.fillRect(0, 0, window.innerWidth, window.innerHeight);
      }

      const dotOpacity = isDark ? 0.7 : 0.4;
      const baseLineOpacity = isDark ? 0.35 : 0.2;
      const lineOpacity = baseLineOpacity + (chaos * 0.4);

      // Color starts glitching (red/amber) at high chaos
      let colorAccent = isDark ? [100, 200, 255] : [0, 80, 255];
      if (chaos > 0.3 && Math.random() < chaos) {
         colorAccent = [255, 50 + Math.random() * 100, 50]; 
      }

      const colorBase = isDark ? [255, 255, 255] : [0, 0, 0];
      ctx.fillStyle = `rgba(${colorBase[0]}, ${colorBase[1]}, ${colorBase[2]}, ${dotOpacity})`;

      for (let i = 0; i < particles.length; i++) {
        // Adjust particle speed using currentPace to respond to reading speed (cognitive pacing)
        const cachedVx = particles[i].vx;
        const cachedVy = particles[i].vy;
        particles[i].vx *= currentPace;
        particles[i].vy *= currentPace;
        updateParticle(particles[i]);
        // Restore original velocities for next frame context
        particles[i].vx = cachedVx;
        particles[i].vy = cachedVy;
        drawParticle(particles[i]);

        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const distance = Math.sqrt(dx * dx + dy * dy);

          // Connection distance increases dramatically under chaos
          const activeConnRes = connectionDistance * (1 + chaos * 1.5);

          if (distance < activeConnRes) {
            const opacity = (1 - distance / activeConnRes) * lineOpacity;
            ctx.beginPath();

            const distToMouseI = Math.sqrt(
              Math.pow(particles[i].x - mouse.x, 2) +
              Math.pow(particles[i].y - mouse.y, 2),
            );
            if (isMouseActive && distToMouseI < mouseRepelRadius * (1.5 + chaos)) {
              ctx.strokeStyle = `rgba(${colorAccent[0]}, ${colorAccent[1]}, ${colorAccent[2]}, ${opacity * (1.5 + chaos * 2)})`;
              ctx.lineWidth = 1 + chaos * 2;
            } else {
              // Lines randomly turn red if corrupted
              if (chaos > 0.6 && Math.random() > 0.95) {
                 ctx.strokeStyle = `rgba(255, 0, 0, ${opacity})`;
              } else {
                 ctx.strokeStyle = `rgba(${colorBase[0]}, ${colorBase[1]}, ${colorBase[2]}, ${opacity})`;
              }
              ctx.lineWidth = 1;
            }

            ctx.moveTo(particles[i].x, particles[i].y);
            // Glitchy line drawing at max chaos
            if (chaos > 0.8 && Math.random() > 0.8) {
               ctx.lineTo(particles[j].x + (Math.random()-0.5)*50, particles[j].y + (Math.random()-0.5)*50);
            } else {
               ctx.lineTo(particles[j].x, particles[j].y);
            }
            ctx.stroke();
          }
        }
      }

      animationFrameId = requestAnimationFrame(animate);
    };

    const handleMouseMove = (e) => {
      mouse.x = e.clientX;
      mouse.y = e.clientY;
      isMouseActive = true;
    };

    const handleMouseLeave = () => {
      isMouseActive = false;
      mouse.x = -1000;
      mouse.y = -1000;
    };

    window.addEventListener("resize", resize);
    window.addEventListener("mousemove", handleMouseMove);
    window.addEventListener("mouseout", handleMouseLeave);

    resize();
    animate();

    return () => {
      window.removeEventListener("resize", resize);
      window.removeEventListener("mousemove", handleMouseMove);
      window.removeEventListener("mouseout", handleMouseLeave);
      cancelAnimationFrame(animationFrameId);
    };
  }, [isDark]);

  const chaosFactor = Math.pow(intensity / 100, 2);
  const filterStyle = intensity > 0 
    ? `hue-rotate(${chaosFactor * 90}deg) contrast(${100 + chaosFactor * 100}%) invert(${intensity > 85 && Math.random() > 0.6 ? 100 : 0}%) blur(${chaosFactor * 3}px)`
    : "none";

  // Shake effect for the entire canvas
  const shakeX = (Math.random() - 0.5) * chaosFactor * 40;
  const shakeY = (Math.random() - 0.5) * chaosFactor * 40;

  return (
    <canvas
      ref={canvasRef}
      style={{ filter: filterStyle, transform: `translate(${shakeX}px, ${shakeY}px) scale(${1 + chaosFactor * 0.1})` }}
      className={`fixed inset-0 z-0 pointer-events-none transition-opacity duration-1000 ${isDark ? "opacity-100 mix-blend-screen" : "opacity-100 mix-blend-multiply"}`}
      aria-hidden="true"
    />
  );
};

export default ChaosCanvas;

import React, { useRef, useState, useEffect } from "react";
import { Copy, Check } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

/**
 * Premium Contact Scratch Component
 * Parity with Framer Motion premium reference.
 * Achieves 0 input lag by discarding requestAnimationFrame and pixel loops
 * in favor of synchronous stroke interpolation.
 */
const ContactScratch = ({ email = "fadly.uzzaki@gmail.com" }) => {
  const canvasRef = useRef(null);
  const [isScratched, setIsScratched] = useState(false);
  const [isDrawing, setIsDrawing] = useState(false);
  const [copied, setCopied] = useState(false);
  const lastPos = useRef(null);

  const canvasConfig = { width: 300, height: 50 };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");

    // Smooth rendering
    ctx.imageSmoothingEnabled = true;

    const computedStyle = getComputedStyle(document.documentElement);
    const colorDark = computedStyle.getPropertyValue('--text-primary').trim() || "black";
    const colorMid = computedStyle.getPropertyValue('--text-secondary').trim() || "gray";
    const colorLight = computedStyle.getPropertyValue('--border-color').trim() || "silver";

    // High performance metallic foil linear-gradient base
    const grad = ctx.createLinearGradient(0, 0, canvas.width, canvas.height);
    grad.addColorStop(0, colorDark);
    grad.addColorStop(0.3, colorMid);
    grad.addColorStop(0.7, colorDark);
    grad.addColorStop(1, colorMid);
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Grid overlays for tech-aesthetic (100x faster than random noise pixels)
    ctx.strokeStyle = "rgba(255,255,255,0.06)";
    ctx.lineWidth = 1;
    for (let x = 0; x < canvas.width; x += 15) {
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, canvas.height);
      ctx.stroke();
    }
    for (let y = 0; y < canvas.height; y += 15) {
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(canvas.width, y);
      ctx.stroke();
    }

    // Centered typography
    const textBase = computedStyle.getPropertyValue('--bg-void').trim() || "white";
    ctx.fillStyle = textBase;
    ctx.font = "bold 12px monospace";
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.letterSpacing = "2px";
    ctx.fillText("[ SCRATCH TO REVEAL ]", canvas.width / 2, canvas.height / 2);
  }, [isScratched]);

  const handleCopy = () => {
    navigator.clipboard.writeText(email);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const checkScratchedPercentage = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");

    try {
      // Extremely lightweight alpha sampling (stride 64)
      const pixels = ctx.getImageData(0, 0, canvas.width, canvas.height).data;
      let transparent = 0;
      let total = 0;

      for (let i = 3; i < pixels.length; i += 64) {
        total++;
        if (pixels[i] < 128) transparent++;
      }

      if (transparent / total > 0.45) {
        setIsScratched(true);
      }
    } catch { /* fallback ignored */ }
  };

  const scratch = (x, y) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");

    // Buttery smooth thick brush settings
    ctx.globalCompositeOperation = "destination-out";
    ctx.lineWidth = 50; 
    ctx.lineCap = "round";
    ctx.lineJoin = "round";
    // Soft blurring blends the strokes cleanly
    ctx.shadowBlur = 15;
    ctx.shadowColor = "black";

    ctx.beginPath();
    if (lastPos.current) {
      // Quadratic Bezier interpolation for sweeping seamless strokes
      const midPoint = {
        x: lastPos.current.x + (x - lastPos.current.x) / 2,
        y: lastPos.current.y + (y - lastPos.current.y) / 2
      };
      ctx.moveTo(lastPos.current.x, lastPos.current.y);
      ctx.quadraticCurveTo(lastPos.current.x, lastPos.current.y, midPoint.x, midPoint.y);
      ctx.lineTo(x, y);
      ctx.stroke();
    } else {
      ctx.arc(x, y, 25, 0, Math.PI * 2);
      ctx.fill();
    }
    lastPos.current = { x, y };

    // Throttle check
    if (Math.random() > 0.85) {
      checkScratchedPercentage();
    }
  };

  const getCoordinates = (e) => {
    const canvas = canvasRef.current;
    if (!canvas) return [0, 0];
    const rect = canvas.getBoundingClientRect();
    const clientX = e.touches && e.touches.length > 0 ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches && e.touches.length > 0 ? e.touches[0].clientY : e.clientY;
    return [clientX - rect.left, clientY - rect.top];
  };

  const startDrawing = (e) => {
    setIsDrawing(true);
    const [x, y] = getCoordinates(e);
    scratch(x, y);
  };

  const draw = (e) => {
    if (!isDrawing) return;
    // Synchronous execution (NO requestAnimationFrame latency) guarantees 0ms input lag
    const [x, y] = getCoordinates(e);
    scratch(x, y);
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    setIsDrawing(false);
    lastPos.current = null;
    checkScratchedPercentage();
  };

  return (
    <div className="inline-block mt-4">
      <div 
        className="relative flex items-center justify-between bg-[var(--bg-void)] border border-[var(--border-color)] overflow-hidden rounded-sm select-none"
        style={{ width: canvasConfig.width, height: canvasConfig.height }}
      >

        {/* Underlying Secret Layer (Framer Scale Reveal) */}
        <motion.div 
          className="absolute inset-0 flex items-center justify-between px-4 z-0 bg-zinc-900 shadow-inner"
          initial={false}
          animate={{ scale: isScratched ? 1 : 0.95, opacity: isScratched ? 1 : 0.5 }}
          transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
        >
          <div className="absolute inset-0 bg-[var(--brand)]/10 pointer-events-none" />
          <span className="font-mono text-sm tracking-widest text-white relative z-10 selection:bg-white/20 font-bold">
            {email}
          </span>
          <button
            onClick={handleCopy}
            className="relative z-10 p-1.5 hover:bg-white/10 dark:hover:bg-zinc-800 rounded transition-colors"
            title="Copy to clipboard"
          >
            {copied ? (
              <Check size={14} className="text-[var(--brand)]" />
            ) : (
              <Copy size={14} className="text-zinc-400 hover:text-white" />
            )}
          </button>
        </motion.div>

        {/* Scratch Canvas Overlay (Framer Physics Exit) */}
        <AnimatePresence>
          {!isScratched && (
            <motion.canvas
              ref={canvasRef}
              width={canvasConfig.width}
              height={canvasConfig.height}
              className="absolute inset-0 z-10 w-full h-full cursor-crosshair touch-none"
              // Smooth physics exit precisely matching Framer components
              exit={{ opacity: 0, scale: 1.05, filter: "blur(4px)" }}
              transition={{ duration: 0.8, ease: "easeOut" }}
              onPointerDown={startDrawing}
              onPointerMove={draw}
              onPointerUp={stopDrawing}
              onPointerLeave={stopDrawing}
              onPointerCancel={stopDrawing}
            />
          )}
        </AnimatePresence>
      </div>

      {/* Help text */}
      <motion.div 
        layout
        className="mt-2 flex items-center gap-2 font-mono text-xs text-[var(--text-secondary)]"
      >
        <span className="text-[var(--brand)]">guest@system:~$</span>
        <motion.span 
          key={isScratched ? "secure" : "decrypt"}
          initial={{ opacity: 0, y: 5 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.3 }}
        >
          {isScratched ? "Connection secure." : "Decrypt payload manually..."}
        </motion.span>
      </motion.div>
    </div>
  );
};

export default ContactScratch;

import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";

import {
  ArrowUpRight,
  Cpu,
  Activity,
  Calendar,
  BookOpen,
  Layers,
} from "lucide-react";
import { useTheme } from "../context/ThemeContext";
import ProjectCard from "./ProjectCard";
import BlindsReveal from "./BlindsReveal";

const MOTION_CONFIG = {
  HOVER_SPRING: { type: "spring", stiffness: 300, damping: 20 },
  IDLE_SYSTEM: { duration: 4, repeat: Infinity, ease: "easeInOut" },
  IDLE_COSMIC: { duration: 5, repeat: Infinity, ease: "easeInOut" },
  IDLE_BRUTALIST: { duration: 3.5, repeat: Infinity, ease: "easeInOut" },
  IDLE_BENTO: { duration: 4.5, repeat: Infinity, ease: "easeInOut" },
};

const VentureCard = ({ project, isIndonesian, onClick }) => {
  const { isDark } = useTheme();
  const [isManualHover, setIsManualHover] = useState(false);
  const [isAutoHover, setIsAutoHover] = useState(false);
  const containerRef = React.useRef(null);

  const isHovered = isManualHover || isAutoHover;

  useEffect(() => {
    const isMobile =
      window.innerWidth < 768 ||
      "ontouchstart" in window ||
      navigator.maxTouchPoints > 0;

    if (!isMobile) return;

    let intervalId;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsAutoHover(true);
          intervalId = setInterval(() => {
            setIsAutoHover((prev) => !prev);
          }, 4000);
        } else {
          setIsAutoHover(false);
          if (intervalId) clearInterval(intervalId);
        }
      },
      { threshold: 0.6 }
    );

    if (containerRef.current) observer.observe(containerRef.current);

    return () => {
      if (intervalId) clearInterval(intervalId);
      if (containerRef.current) observer.unobserve(containerRef.current);
    };
  }, [project.id]);

  const resolveText = (field) => {
    if (!field) return "";
    if (typeof field === "object") {
      return isIndonesian ? field.id || field.en : field.en;
    }
    return field;
  };

  const title =
    isIndonesian && project.title_id
      ? project.title_id
      : resolveText(project.title);
  const desc =
    isIndonesian && project.desc_id
      ? project.desc_id
      : resolveText(project.desc);

  // Dynamic Archetype Selection
  const commonProps = {
    project,
    title,
    desc,
    isIndonesian,
    onClick,
    isHovered,
    ref: containerRef,
    onMouseEnter: () => setIsManualHover(true),
    onMouseLeave: () => setIsManualHover(false),
  };

  switch (project.id) {
    case "human-algorithm":
      return <SystemCoreCard {...commonProps} isDark={isDark} />;
    case "dolphi":
      return <CosmicPopCard {...commonProps} isDark={isDark} />;
    case "productivity-illusion":
      return <BrutalistCard {...commonProps} isDark={isDark} />;
    case "year-in-review":
      return <BentoCard {...commonProps} isDark={isDark} />;
    case "interactive-workbook":
      return <BlueprintCard {...commonProps} isDark={isDark} />;
    default:
      return null;
  }
};

// 1. THE SYSTEM CORE (Human Algorithm)
const SystemCoreCard = ({ project, title, desc, onClick, isHovered, isIndonesian, ref, onMouseEnter, onMouseLeave }) => (
  <motion.div
    ref={ref}
    id={`venture-card-${project.id}`}
    onClick={onClick}
    onMouseEnter={onMouseEnter}
    onMouseLeave={onMouseLeave}
    className="group relative h-[450px] rounded-3xl border-2 border-[var(--border-color)] bg-[var(--bg-void)] overflow-hidden cursor-pointer flex flex-col"
    animate={isHovered ? { borderColor: "rgba(var(--bg-surface-rgb), 0.4)", scale: 0.98, y: 0 } : { borderColor: "var(--border-color)", scale: 1, y: [0, -3, 0] }}
    transition={isHovered ? MOTION_CONFIG.HOVER_SPRING : MOTION_CONFIG.IDLE_SYSTEM}
    whileHover={{ borderColor: "rgba(var(--bg-surface-rgb), 0.4)", scale: 0.98 }}
  >
    <BlindsReveal isOpen={isHovered} slats={8} color="var(--bg-void)">
      {/* Terminal Text Background */}
      <div className="absolute inset-0 opacity-5 font-mono text-[8px] leading-none pointer-events-none select-none overflow-hidden p-4 text-[var(--text-primary)]">
        {Array.from({ length: 50 }).map((_, i) => (
          <div key={i} className="mb-1 whitespace-nowrap">
            {`INIT_CORE_PORTFOLIO_V2.9 >> AGENT_00${i} >> STATUS_ACTIVE >> RECURSIVE_TRUE >> PATH=/root/human-algorithm/${project.id}/kernel >> `}
            {Math.floor((i + 1) * project.id.length * 1234567)
              .toString(36)
              .substring(0, 13)}
          </div>
        ))}
      </div>

      {/* Scanning Line */}
